      "content": "// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
const { AppError, sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const statusFilter = req.query.status;
  try {
    const tasks = await service.listTasks(projectId, statusFilter);
    if (!tasks) return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    res.json({ tasks });
  } catch (error) {
    sendError(res, error.status || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title) return sendError(res, 400, 'INVALID_INPUT', 'Title is required');
  try {
    const task = await service.createTask(projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, error.status || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  try {
    const updatedTask = await service.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) return sendError(res, 404, 'NOT_FOUND', 'Task not found');
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, error.status || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;
