      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('../../lib/id');
const projectsService = require('../projects/service');

let tasksStore = {};

async function listTasks(projectId, statusFilter) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  let tasks = Object.values(tasksStore).filter(task => task.projectId === projectId);
  if (statusFilter) {
    tasks = tasks.filter(task => task.status === statusFilter);
  }
  return tasks;
}

async function createTask(projectId, title) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) throw new AppError(404, 'NOT_FOUND', 'Project not found');
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'todo' };
  tasksStore[taskId] = task;
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  if (!['todo', 'done'].includes(status)) throw new AppError(400, 'INVALID_INPUT', 'Invalid task status');
  const task = tasksStore[taskId];
  if (!task || task.projectId !== projectId) return null;
  task.status = status;
  return task;
}

module.exports = { listTasks, createTask, updateTaskStatus };
